--- a/relayStore.js
+++ b/relayStore.js
@@ -1,1 +1,174 @@
-
+const fs = require('fs');
+const path = require('path');
+
+const IR_FILES = [
+  'relay_context.md',
+  'compile_brief.md',
+  'project.md',
+  'current_task.md',
+  'decisions.md',
+  'failures.md',
+  'architecture.md',
+  'AGENT_BOOTSTRAP.md',
+  'memory.json',
+  'config.json',
+];
+
+const SKIP_DIRS = new Set(['node_modules', '.git']);
+
+function getRelayDir(workspacePath) {
+  return path.join(path.resolve(workspacePath), '.relay');
+}
+
+function assertRelayPath(relayDir, relPath) {
+  const normalized = path.normalize(relPath).replace(/^(\.\.(\/|\\|$))+/, '');
+  const full = path.resolve(relayDir, normalized);
+  if (!full.startsWith(path.resolve(relayDir))) {
+    throw new Error('Path escapes .relay directory');
+  }
+  return { full, rel: normalized.replace(/\\/g, '/') };
+}
+
+function listRelayFiles(workspacePath, subPath = '') {
+  const relayDir = getRelayDir(workspacePath);
+  if (!fs.existsSync(relayDir)) {
+    throw new Error('Workspace not registered. Run relay init first.');
+  }
+
+  const { full, rel } = assertRelayPath(relayDir, subPath || '.');
+  if (!fs.existsSync(full)) return { path: rel === '.' ? '' : rel, entries: [] };
+
+  const stat = fs.statSync(full);
+  if (!stat.isDirectory()) {
+    return { path: rel === '.' ? '' : rel, entries: [] };
+  }
+
+  const entries = fs
+    .readdirSync(full, { withFileTypes: true })
+    .filter((e) => !e.name.startsWith('.') || e.name === '.relay-hook-continuing')
+    .filter((e) => !SKIP_DIRS.has(e.name))
+    .map((e) => {
+      const childRel = rel === '.' || !rel ? e.name : `${rel}/${e.name}`;
+      const childFull = path.join(full, e.name);
+      const childStat = fs.statSync(childFull);
+      return {
+        name: e.name,
+        path: childRel.replace(/\\/g, '/'),
+        type: childStat.isDirectory() ? 'dir' : 'file',
+        size: childStat.isFile() ? childStat.size : null,
+        updatedAt: childStat.mtime.toISOString(),
+      };
+    })
+    .sort((a, b) => {
+      if (a.type !== b.type) return a.type === 'dir' ? -1 : 1;
+      return a.name.localeCompare(b.name);
+    });
+
+  return { path: rel === '.' ? '' : rel, entries };
+}
+
+function readRelayFile(workspacePath, relPath) {
+  const relayDir = getRelayDir(workspacePath);
+  if (!fs.existsSync(relayDir)) {
+    throw new Error('Workspace not registered. Run relay init first.');
+  }
+
+  const { full, rel } = assertRelayPath(relayDir, relPath);
+  if (!fs.existsSync(full) || !fs.statSync(full).isFile()) {
+    throw new Error(`File not found: ${rel}`);
+  }
+
+  const stat = fs.statSync(full);
+  const content = fs.readFileSync(full, 'utf-8');
+  return {
+    path: rel,
+    content,
+    size: stat.size,
+    updatedAt: stat.mtime.toISOString(),
+  };
+}
+
+function writeRelayFile(workspacePath, relPath, content) {
+  const relayDir = getRelayDir(workspacePath);
+  if (!fs.existsSync(relayDir)) {
+    throw new Error('Workspace not registered. Run relay init first.');
+  }
+
+  const { full, rel } = assertRelayPath(relayDir, relPath);
+  fs.mkdirSync(path.dirname(full), { recursive: true });
+  fs.writeFileSync(full, content, 'utf-8');
+  const stat = fs.statSync(full);
+  return {
+    path: rel,
+    size: stat.size,
+    updatedAt: stat.mtime.toISOString(),
+  };
+}
+
+function buildRelayTree(workspacePath, maxDepth = 3) {
+  const relayDir = getRelayDir(workspacePath);
+  if (!fs.existsSync(relayDir)) return [];
+
+  function walk(dir, rel, depth) {
+    if (depth > maxDepth) return [];
+    let entries;
+    try {
+      entries = fs.readdirSync(dir, { withFileTypes: true });
+    } catch (_) {
+      return [];
+    }
+
+    return entries
+      .filter((e) => !SKIP_DIRS.has(e.name))
+      .filter((e) => !e.name.startsWith('.') || IR_FILES.includes(e.name))
+      .map((e) => {
+        const childRel = rel ? `${rel}/${e.name}` : e.name;
+        const childFull = path.join(dir, e.name);
+        if (e.isDirectory()) {
+          return {
+            name: e.name,
+            path: childRel.replace(/\\/g, '/'),
+            type: 'dir',
+            children: walk(childFull, childRel, depth + 1),
+          };
+        }
+        const stat = fs.statSync(childFull);
+        return {
+          name: e.name,
+          path: childRel.replace(/\\/g, '/'),
+          type: 'file',
+          size: stat.size,
+          updatedAt: stat.mtime.toISOString(),
+        };
+      })
+      .sort((a, b) => {
+        if (a.type !== b.type) return a.type === 'dir' ? -1 : 1;
+        return a.name.localeCompare(b.name);
+      });
+  }
+
+  return walk(relayDir, '', 0);
+}
+
+function readIrFiles(workspacePath) {
+  const relayDir = getRelayDir(workspacePath);
+  const out = {};
+  for (const name of IR_FILES) {
+    const full = path.join(relayDir, name);
+    if (fs.existsSync(full) && fs.statSync(full).isFile()) {
+      out[name] = fs.readFileSync(full, 'utf-8');
+    }
+  }
+  return out;
+}
+
+module.exports = {
+  IR_FILES,
+  getRelayDir,
+  listRelayFiles,
+  readRelayFile,
+  writeRelayFile,
+  buildRelayTree,
+  readIrFiles,
+};
+

--- a/relayAuth.js
+++ b/relayAuth.js
@@ -1,1 +1,27 @@
-
+function getApiKey() {
+  return process.env.RELAY_API_KEY || '';
+}
+
+function requireApiKey(req, res, next) {
+  const configured = getApiKey();
+  if (!configured) return next();
+
+  const header = req.headers.authorization || '';
+  const token = header.startsWith('Bearer ') ? header.slice(7) : req.headers['x-relay-api-key'];
+  if (token && token === configured) return next();
+
+  return res.status(401).json({
+    error: 'Invalid or missing API key. Set Authorization: Bearer <RELAY_API_KEY>.',
+  });
+}
+
+function isAuthEnabled() {
+  return Boolean(getApiKey());
+}
+
+module.exports = {
+  getApiKey,
+  requireApiKey,
+  isAuthEnabled,
+};
+

--- a/relayDashboard.js
+++ b/relayDashboard.js
@@ -1,1 +1,119 @@
-
+const { getMemory } = require('../relay');
+const { readIrFiles, buildRelayTree } = require('./relayStore');
+
+function countByKind(events) {
+  const counts = { message: 0, code_edit: 0, artifact: 0, other: 0 };
+  for (const e of events) {
+    const k = e.kind || 'message';
+    if (counts[k] !== undefined) counts[k] += 1;
+    else counts.other += 1;
+  }
+  return counts;
+}
+
+function countBySource(events) {
+  const counts = {};
+  for (const e of events) {
+    const src = e.source || 'Unknown';
+    counts[src] = (counts[src] || 0) + 1;
+  }
+  return counts;
+}
+
+function groupEventsByDay(events) {
+  const groups = new Map();
+  for (const e of events) {
+    const day = e.ts ? e.ts.slice(0, 10) : 'unknown';
+    if (!groups.has(day)) groups.set(day, []);
+    groups.get(day).push(e);
+  }
+  return [...groups.entries()]
+    .sort((a, b) => b[0].localeCompare(a[0]))
+    .map(([day, items]) => ({ day, count: items.length, events: items }));
+}
+
+function paginateEvents(events, { limit = 40, offset = 0, kind, source, role } = {}) {
+  let filtered = events;
+  if (kind === 'code_edit') {
+    filtered = filtered.filter((e) => e.kind === 'code_edit' || e.kind === 'artifact');
+  } else if (kind && kind !== 'all') {
+    filtered = filtered.filter((e) => e.kind === kind);
+  }
+  if (source && source !== 'all') {
+    filtered = filtered.filter((e) => e.source === source);
+  }
+  if (role === 'user' || role === 'assistant') {
+    filtered = filtered.filter((e) => e.role === role);
+  }
+
+  const total = filtered.length;
+  const slice = filtered.slice(Math.max(0, offset), Math.max(0, offset) + limit);
+  return { total, offset, limit, events: slice };
+}
+
+function buildAgentSummary(memory) {
+  const agents = memory.agents || {};
+  return Object.entries(agents).map(([name, data]) => ({
+    name,
+    status: data.status || 'idle',
+    eventCount: data.eventCount || (data.events || []).length,
+    transcriptPath: data.transcriptPath || null,
+  }));
+}
+
+function buildDashboard(workspacePath, options = {}) {
+  const memory = getMemory(workspacePath);
+  const timeline = Array.isArray(memory.timeline) ? memory.timeline : [];
+  const sorted = [...timeline].sort((a, b) => new Date(a.ts || 0) - new Date(b.ts || 0));
+
+  const ir = readIrFiles(workspacePath);
+  const tree = buildRelayTree(workspacePath);
+
+  const recentEdits = sorted
+    .filter((e) => e.kind === 'code_edit' || e.kind === 'artifact')
+    .slice(-20)
+    .reverse();
+
+  const activityPage = paginateEvents(sorted, {
+    limit: options.limit || 40,
+    offset: options.offset || 0,
+    kind: options.kind,
+    source: options.source,
+    role: options.role,
+  });
+
+  return {
+    workspace: memory.workspace || workspacePath,
+    lastSync: memory.lastSync || null,
+    stats: {
+      totalEvents: sorted.length,
+      byKind: countByKind(sorted),
+      bySource: countBySource(sorted),
+      connectedAgents: buildAgentSummary(memory).filter((a) => a.status === 'connected').length,
+    },
+    agents: buildAgentSummary(memory),
+    handoff: {
+      markdown: ir['relay_context.md'] || '',
+      updatedAt: memory.lastSync,
+    },
+    ir: {
+      project: ir['project.md'] || '',
+      currentTask: ir['current_task.md'] || '',
+      decisions: ir['decisions.md'] || '',
+      failures: ir['failures.md'] || '',
+      architecture: ir['architecture.md'] || '',
+      compileBrief: ir['compile_brief.md'] || '',
+    },
+    recentEdits,
+    activity: activityPage,
+    days: groupEventsByDay(sorted).slice(0, 14),
+    fileTree: tree,
+  };
+}
+
+module.exports = {
+  buildDashboard,
+  paginateEvents,
+  groupEventsByDay,
+};
+

