-
+const path = require('path');
+const express = require('express');
+const cors = require('cors');
+const {
+  registerWorkspace,
+  sendHandshake,
+  connectAgent,
+  syncWorkspace,
+  startWatcher,
+  getMemory,
+  getRelayContext,
+  getCompileBrief,
+} = require('./relay');
+const { buildDashboard } = require('./lib/relayDashboard');
+const { listRelayFiles, readRelayFile, writeRelayFile } = require('./lib/relayStore');
+const { requireApiKey, isAuthEnabled } = require('./lib/relayAuth');
+
+const PACKAGE_ROOT = path.join(__dirname, '..');
+const UI_ROOT = path.join(PACKAGE_ROOT, 'basic_frontend');
+
+function createApp() {
+  const app = express();
+  app.use(cors());
+  app.use(express.json({ limit: '2mb' }));
+
+  app.use(express.static(UI_ROOT));
+
+  app.get('/', (_req, res) => {
+    res.sendFile(path.join(UI_ROOT, 'index.html'));
+  });
+
+  app.get('/api/health', (_req, res) => {
+    res.json({
+      ok: true,
+      authRequired: isAuthEnabled(),
+      version: require('../package.json').version,
+    });
+  });
+
+  app.post('/api/register', (req, res) => {
+    const { workspacePath } = req.body;
+    if (!workspacePath) return res.status(400).json({ error: 'workspacePath is required' });
+    try {
+      const config = registerWorkspace(workspacePath);
+      startWatcher(workspacePath);
+      getRelayContext(workspacePath);
+      res.json({ ok: true, config });
+    } catch (err) {
+      res.status(500).json({ error: err.message });
+    }
+  });
+
+  app.post('/api/handshake', (req, res) => {
+    const { workspacePath, agent } = req.body;
+    if (!workspacePath || !agent) {
+      return res.status(400).json({ error: 'workspacePath and agent are required' });
+    }
+    try {
+      const token = sendHandshake(workspacePath, agent);
+      res.json({ ok: true, token, message: `Handshake token sent to ${agent} automatically.` });
+    } catch (err) {
+      res.status(500).json({ error: err.message });
+    }
+  });
+
+  app.post('/api/connect', (req, res) => {
+    const { workspacePath, agent } = req.body;
+    if (!workspacePath || !agent) {
+      return res.status(400).json({ error: 'workspacePath and agent is required' });
+    }
+    try {
+      const result = connectAgent(workspacePath, agent);
+      startWatcher(workspacePath);
+      res.json({ ok: true, ...result });
+    } catch (err) {
+      res.status(500).json({ error: err.message });
+    }
+  });
+
+  app.post('/api/sync', (req, res) => {
+    const { workspacePath } = req.body;
+    if (!workspacePath) return res.status(400).json({ error: 'workspacePath is required' });
+    try {
+      const result = syncWorkspace(workspacePath);
+      getRelayContext(workspacePath);
+      res.json({ ok: true, ...result });
+    } catch (err) {
+      res.status(500).json({ error: err.message });
+    }
+  });
+
+  app.get('/api/memory', (req, res) => {
+    const { workspacePath } = req.query;
+    if (!workspacePath) return res.status(400).json({ error: 'workspacePath is required' });
+    try {
+      const memory = getMemory(workspacePath);
+      res.json({ ok: true, memory });
+    } catch (err) {
+      res.status(500).json({ error: err.message });
+    }
+  });
+
+  app.get('/api/dashboard', (req, res) => {
+    const { workspacePath, limit, offset, kind, source, role } = req.query;
+    if (!workspacePath) return res.status(400).json({ error: 'workspacePath is required' });
+    try {
+      const dashboard = buildDashboard(workspacePath, {
+        limit: limit ? Number(limit) : 40,
+        offset: offset ? Number(offset) : 0,
+        kind,
+        source,
+        role,
+      });
+      res.json({ ok: true, dashboard });
+    } catch (err) {
+      res.status(500).json({ error: err.message });
+    }
+  });
+
+  app.get('/api/context', (req, res) => {
+    const { workspacePath } = req.query;
+    if (!workspacePath) return res.status(400).json({ error: 'workspacePath is required' });
+    try {
+      const result = getRelayContext(workspacePath);
+      res.json({ ok: true, context: result.context, markdown: result.markdown });
+    } catch (err) {
+      res.status(500).json({ error: err.message });
+    }
+  });
+
+  app.get('/api/compile', (req, res) => {
+    const { workspacePath } = req.query;
+    if (!workspacePath) return res.status(400).json({ error: 'workspacePath is required' });
+    try {
+      const result = getCompileBrief(workspacePath);
+      res.json({ ok: true, brief: result.brief, markdown: result.markdown });
+    } catch (err) {
+      res.status(500).json({ error: err.message });
+    }
+  });
+
+  app.get('/api/relay/files', requireApiKey, (req, res) => {
+    const { workspacePath, path: subPath } = req.query;
+    if (!workspacePath) return res.status(400).json({ error: 'workspacePath is required' });
+    try {
+      const listing = listRelayFiles(workspacePath, subPath || '');
+      res.json({ ok: true, ...listing });
+    } catch (err) {
+      res.status(500).json({ error: err.message });
+    }
+  });
+
+  app.get('/api/relay/file', requireApiKey, (req, res) => {
+    const { workspacePath, path: filePath } = req.query;
+    if (!workspacePath || !filePath) {
+      return res.status(400).json({ error: 'workspacePath and path are required' });
+    }
+    try {
+      const file = readRelayFile(workspacePath, filePath);
+      res.json({ ok: true, file });
+    } catch (err) {
+      res.status(404).json({ error: err.message });
+    }
+  });
+
+  app.put('/api/relay/file', requireApiKey, (req, res) => {
+    const { workspacePath, path: filePath, content } = req.body;
+    if (!workspacePath || !filePath || content === undefined) {
+      return res.status(400).json({ error: 'workspacePath, path, and content are required' });
+    }
+    try {
+      const file = writeRelayFile(workspacePath, filePath, content);
+      res.json({ ok: true, file });
+    } catch (err) {
+      res.status(500).json({ error: err.message });
+    }
+  });
+
+  return app;
+}
+
+function startServer(options = {}) {
+  const PORT = options.port || Number(process.env.RELAY_PORT) || 3001;
+  const app = createApp();
+
+  return app.listen(PORT, () => {
+    console.log('');
+    console.log(`🔗 Relay running at http://localhost:${PORT}/`);
+    console.log(`   UI + API on the same port`);
+    if (isAuthEnabled()) console.log('   API key auth enabled (RELAY_API_KEY)');
+    console.log('');
+  });
+}
+
+if (require.main === module) {
+  startServer();
+}
+
+module.exports = { createApp, startServer };
+

--- a/server.js
+++ b/server.js
@@ -1,1 +1,229 @@
-
+#!/usr/bin/env node
+/**
+ * Relay MCP server — agents explore .relay via tools (local files or remote API).
+ *
+ * Local:  RELAY_WORKSPACE_PATH=/path/to/project
+ * Remote: RELAY_API_URL=https://api.relay.dev  RELAY_API_KEY=...
+ */
+const readline = require('readline');
+const path = require('path');
+
+const BACKEND = path.join(__dirname, '..');
+const store = require(path.join(BACKEND, 'lib', 'relayStore'));
+const { syncWorkspace, getRelayContext } = require(path.join(BACKEND, 'relay'));
+
+const MODE = process.env.RELAY_API_URL ? 'remote' : 'local';
+const WORKSPACE = process.env.RELAY_WORKSPACE_PATH
+  ? path.resolve(process.env.RELAY_WORKSPACE_PATH)
+  : process.cwd();
+const API_URL = (process.env.RELAY_API_URL || '').replace(/\/$/, '');
+const API_KEY = process.env.RELAY_API_KEY || '';
+
+const TOOLS = [
+  {
+    name: 'relay_list_files',
+    description: 'List files and folders inside the project .relay directory. Use path="" for root.',
+    inputSchema: {
+      type: 'object',
+      properties: {
+        path: { type: 'string', description: 'Relative path within .relay (empty for root)' },
+      },
+    },
+  },
+  {
+    name: 'relay_read_file',
+    description: 'Read any file inside .relay (markdown, json, etc.).',
+    inputSchema: {
+      type: 'object',
+      properties: {
+        path: { type: 'string', description: 'Relative file path, e.g. relay_context.md' },
+      },
+      required: ['path'],
+    },
+  },
+  {
+    name: 'relay_write_file',
+    description: 'Write or update a file inside .relay (IR markdown, etc.).',
+    inputSchema: {
+      type: 'object',
+      properties: {
+        path: { type: 'string', description: 'Relative file path' },
+        content: { type: 'string', description: 'Full file content' },
+      },
+      required: ['path', 'content'],
+    },
+  },
+  {
+    name: 'relay_get_context',
+    description: 'Regenerate and return relay_context.md handoff bundle.',
+    inputSchema: { type: 'object', properties: {} },
+  },
+  {
+    name: 'relay_sync',
+    description: 'Sync agent transcripts into memory.json and refresh compile brief.',
+    inputSchema: { type: 'object', properties: {} },
+  },
+];
+
+async function apiFetch(method, urlPath, body) {
+  const headers = { 'Content-Type': 'application/json' };
+  if (API_KEY) headers.Authorization = `Bearer ${API_KEY}`;
+
+  const res = await fetch(`${API_URL}${urlPath}`, {
+    method,
+    headers,
+    body: body ? JSON.stringify(body) : undefined,
+  });
+  const data = await res.json();
+  if (!res.ok) throw new Error(data.error || res.statusText);
+  return data;
+}
+
+async function listFiles(subPath) {
+  if (MODE === 'remote') {
+    const q = new URLSearchParams({
+      workspacePath: WORKSPACE,
+      path: subPath || '',
+    });
+    const data = await apiFetch('GET', `/api/relay/files?${q}`);
+    return data;
+  }
+  return store.listRelayFiles(WORKSPACE, subPath || '');
+}
+
+async function readFile(relPath) {
+  if (MODE === 'remote') {
+    const q = new URLSearchParams({ workspacePath: WORKSPACE, path: relPath });
+    const data = await apiFetch('GET', `/api/relay/file?${q}`);
+    return data.file;
+  }
+  return store.readRelayFile(WORKSPACE, relPath);
+}
+
+async function writeFile(relPath, content) {
+  if (MODE === 'remote') {
+    const data = await apiFetch('PUT', '/api/relay/file', {
+      workspacePath: WORKSPACE,
+      path: relPath,
+      content,
+    });
+    return data.file;
+  }
+  return store.writeRelayFile(WORKSPACE, relPath, content);
+}
+
+async function getContext() {
+  if (MODE === 'remote') {
+    const q = new URLSearchParams({ workspacePath: WORKSPACE });
+    const data = await apiFetch('GET', `/api/context?${q}`);
+    return { markdown: data.markdown, context: data.context };
+  }
+  return getRelayContext(WORKSPACE);
+}
+
+async function syncRelay() {
+  if (MODE === 'remote') {
+    return apiFetch('POST', '/api/sync', { workspacePath: WORKSPACE });
+  }
+  const result = syncWorkspace(WORKSPACE);
+  getRelayContext(WORKSPACE);
+  return result;
+}
+
+async function callTool(name, args) {
+  switch (name) {
+    case 'relay_list_files': {
+      const listing = await listFiles(args.path || '');
+      return {
+        content: [{ type: 'text', text: JSON.stringify(listing, null, 2) }],
+      };
+    }
+    case 'relay_read_file': {
+      const file = await readFile(args.path);
+      return {
+        content: [{ type: 'text', text: file.content }],
+      };
+    }
+    case 'relay_write_file': {
+      const file = await writeFile(args.path, args.content);
+      return {
+        content: [{ type: 'text', text: `Wrote ${file.path} (${file.size} bytes)` }],
+      };
+    }
+    case 'relay_get_context': {
