+  }
+  let data: Record<string, unknown> = {};
+  try {
+    data = await res.json();
+  } catch {
+    /* non-JSON */
+  }
+  if (!res.ok || data.ok === false) {
+    throw new Error((data.error as string) || `Relay request failed (${res.status})`);
+  }
+  return data as T;
