+            <div key={section.key} className={styles.section}>
+              <button
+                type="button"
+                className={`${styles.sectionHead} ${isOpen ? styles.sectionHeadOpen : ''}`}
+                onClick={() => setOpen(isOpen ? '' : section.key)}
