+export const RELAY_URL =
+  process.env.NEXT_PUBLIC_RELAY_URL || 'http://localhost:3001';
+
+export type AgentId =
+  | 'Antigravity'
+  | 'Codex'
+  | 'Claude Code'
+  | 'GitHub Copilot'
+  | 'Cursor';
+
+export interface AgentMeta {
