-}
+function dashboardFingerprint(d: RelayDashboard | null): string {
+  if (!d) return '';
+  const ir = d.ir || ({} as RelayDashboardIr);
+  return [
+    d.lastSync || '',
+    d.handoff?.markdown?.length || 0,
+    ir.currentTask?.length || 0,
+    ir.decisions?.length || 0,
+    ir.failures?.length || 0,
+    ir.project?.length || 0,
+  ].join(':');
+}

